#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding audiology-assessment (14 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    age:int \
    sex:string! \
    ethnicity:string! \
    occupation:string! \
    postcode:string! \
    referring_clinician:string! \
    referral_source:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    primary_complaint:text! \
    complaint_duration:string! \
    onset_type:string! \
    laterality:string! \
    ear_most_affected:string! \
    difficulty_in_noise:string! \
    difficulty_on_phone:string! \
    difficulty_with_television:string! \
    asks_others_to_repeat:string! \
    additional_concerns:text! \
    --htmx

cargo loco generate scaffold assessment_hearing_history \
    assessment:references \
    previous_hearing_test:string! \
    previous_test_date:date \
    previous_test_results:text! \
    noise_exposure_history:string! \
    noise_exposure_details:text! \
    occupational_noise_exposure:string! \
    recreational_noise_exposure:string! \
    uses_hearing_protection:string! \
    military_service:string! \
    ear_infections_history:string! \
    ear_surgery_history:string! \
    ear_surgery_details:text! \
    ototoxic_medication_exposure:string! \
    ototoxic_medication_details:text! \
    family_history_hearing_loss:string! \
    family_hearing_loss_details:text! \
    --htmx

cargo loco generate scaffold assessment_audiometric_results \
    assessment:references \
    right_ac_250hz:double \
    right_ac_500hz:double \
    right_ac_1000hz:double \
    right_ac_2000hz:double \
    right_ac_4000hz:double \
    right_ac_8000hz:double \
    left_ac_250hz:double \
    left_ac_500hz:double \
    left_ac_1000hz:double \
    left_ac_2000hz:double \
    left_ac_4000hz:double \
    left_ac_8000hz:double \
    right_bc_500hz:double \
    right_bc_1000hz:double \
    right_bc_2000hz:double \
    right_bc_4000hz:double \
    left_bc_500hz:double \
    left_bc_1000hz:double \
    left_bc_2000hz:double \
    left_bc_4000hz:double \
    right_pta_db:double \
    left_pta_db:double \
    right_hearing_type:string! \
    left_hearing_type:string! \
    right_srt_db:double \
    left_srt_db:double \
    right_word_recognition_percent:double \
    left_word_recognition_percent:double \
    right_tympanogram_type:string! \
    left_tympanogram_type:string! \
    test_date:date \
    audiologist_name:string! \
    audiometric_notes:text! \
    --htmx

cargo loco generate scaffold assessment_tinnitus \
    assessment:references \
    has_tinnitus:string! \
    tinnitus_laterality:string! \
    tinnitus_type:string! \
    tinnitus_description:text! \
    tinnitus_onset:string! \
    tinnitus_duration:string! \
    tinnitus_constancy:string! \
    tinnitus_severity:int \
    tinnitus_impact_on_sleep:string! \
    tinnitus_impact_on_concentration:string! \
    tinnitus_impact_on_mood:string! \
    tinnitus_management:text! \
    --htmx

cargo loco generate scaffold assessment_vestibular_symptoms \
    assessment:references \
    has_dizziness:string! \
    has_vertigo:string! \
    vertigo_type:string! \
    vertigo_duration:string! \
    vertigo_frequency:string! \
    vertigo_triggers:text! \
    has_balance_problems:string! \
    has_falls:string! \
    falls_frequency:string! \
    has_nausea_with_dizziness:string! \
    has_aural_fullness:string! \
    suspected_meniere_disease:string! \
    vestibular_notes:text! \
    --htmx

cargo loco generate scaffold assessment_otoscopic_findings \
    assessment:references \
    right_ear_canal:string! \
    right_ear_canal_notes:text! \
    right_tympanic_membrane:string! \
    right_tympanic_membrane_notes:text! \
    right_cerumen:string! \
    left_ear_canal:string! \
    left_ear_canal_notes:text! \
    left_tympanic_membrane:string! \
    left_tympanic_membrane_notes:text! \
    left_cerumen:string! \
    otoscopy_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    has_diabetes:string! \
    has_cardiovascular_disease:string! \
    has_autoimmune_condition:string! \
    autoimmune_details:text! \
    has_kidney_disease:string! \
    has_neurological_condition:string! \
    neurological_details:text! \
    current_medications:text! \
    ototoxic_medications:text! \
    has_drug_allergies:string! \
    drug_allergy_details:text! \
    other_medical_history:text! \
    --htmx

cargo loco generate scaffold assessment_functional_communication \
    assessment:references \
    communication_difficulty_rating:string! \
    impact_on_work:string! \
    impact_on_social_life:string! \
    impact_on_relationships:string! \
    impact_on_mental_health:string! \
    uses_hearing_aid:string! \
    hearing_aid_type:string! \
    hearing_aid_satisfaction:string! \
    uses_assistive_devices:string! \
    assistive_device_details:text! \
    communication_strategies_used:text! \
    patient_goals:text! \
    referral_recommendations:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    right_pta_db:double \
    left_pta_db:double \
    better_ear_pta_db:double \
    right_hearing_grade:string! \
    left_hearing_grade:string! \
    overall_hearing_grade:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    hearing_grade:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
